import React, { useState, useEffect } from 'react';
import { supabase } from './supabaseClient';
import Dashboard from './Dashboard';
import { submitManualData } from './api'; // Ensure this helper still exists

function App() {
    const [user, setUser] = useState(null);
    const [email, setEmail] = useState('');
    const [password, setPassword] = useState('');
    const [view, setView] = useState('login'); 
    
    // Analysis & Product States
    const [analysisData, setAnalysisData] = useState(null);
    const [productName, setProductName] = useState('');
    const [barcode, setBarcode] = useState('');
    const [isLoading, setIsLoading] = useState(false);
    const [error, setError] = useState(null);

    // Health Quiz States
    const [goal, setGoal] = useState('Energy');
    const [symptoms, setSymptoms] = useState([]);
    const goals = ["Energy", "Immunity", "Cognitive Focus", "Skin Health", "Muscle Recovery", "Longevity", "Gut Health"];
    const symptomList = ["Fatigue", "Stress", "Poor Sleep", "Muscle Cramps", "Brain Fog", "Joint Pain", "Brittle Nails", "Anxiety", "Dry Eyes", "Bloating"];

    useEffect(() => {
        supabase.auth.getSession().then(({ data: { session } }) => {
            setUser(session?.user ?? null);
        });
        const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
            setUser(session?.user ?? null);
            if (session?.user) setView('choice');
        });
        return () => subscription.unsubscribe();
    }, []);

    // --- AUTH HANDLERS ---
    const handleAuth = async (type) => {
        setIsLoading(true);
        const { error } = type === 'login' 
            ? await supabase.auth.signInWithPassword({ email, password })
            : await supabase.auth.signUp({ email, password });
        if (error) alert(error.message);
        setIsLoading(false);
    };

    // --- SCANNING HANDLERS ---
    const handleBarcodeSearch = async (val = barcode) => {
        if (!val) return;
        setIsLoading(true);
        try {
            const response = await fetch(`http://localhost:8000/scan-barcode/${val}`);
            const result = await response.json();
            if (result.status === "success") {
                setAnalysisData(result.data);
                setProductName(result.product_name);
            } else { setError(result.message); }
        } catch (err) { setError("Connection failed."); }
        finally { setIsLoading(false); }
    };

    const handlePhotoUpload = async (e) => {
        const file = e.target.files[0];
        if (!file) return;
        setIsLoading(true);
        setError(null);
        const formData = new FormData();
        formData.append("file", file);
        try {
            const response = await fetch("http://localhost:8000/upload-barcode-photo", {
                method: "POST",
                body: formData
            });
            const result = await response.json();
            if (result.status === "success") {
                setAnalysisData(result.data);
                setProductName(result.product_name);
            } else { setError(result.message); }
        } catch (err) { setError("Photo processing failed."); }
        finally { setIsLoading(false); }
    };

    // --- HEALTH QUIZ HANDLER ---
    const handleQuizSubmit = async () => {
        setIsLoading(true);
        try {
            const response = await submitManualData({ goal, symptoms });
            setAnalysisData(response.data);
            setProductName("Personal Health Profile");
        } catch (err) { setError("Quiz analysis failed."); }
        finally { setIsLoading(false); }
    };

    // --- DIET PLAN PERSISTENCE ---
    const saveToDietPlan = async () => {
        if (!user) return;
        const entry = {
            product_name: productName,
            analysis_json: analysisData,
            user_id: user.id
        };
        const { error } = await supabase.from('diet_logs').insert([entry]);
        if (error) alert("Error saving: " + error.message);
        else alert("Successfully added to your Diet Plan!");
    };

    const resetView = () => {
        setAnalysisData(null);
        setProductName('');
        setBarcode('');
        setError(null);
        setView('choice');
    };

    if (!user) {
        return (
            <div style={styles.container}>
                <h1 style={styles.title}>NutriGen<span style={{color: '#38a169'}}>.</span></h1>
                <div style={styles.card}>
                    <h3>{view === 'login' ? 'Login' : 'Sign Up'}</h3>
                    <input style={styles.input} placeholder="Email" onChange={e => setEmail(e.target.value)} />
                    <input style={styles.input} type="password" placeholder="Password" onChange={e => setPassword(e.target.value)} />
                    <button style={styles.btn} onClick={() => handleAuth(view)}>{isLoading ? '...' : (view === 'login' ? 'Login' : 'Sign Up')}</button>
                    <p onClick={() => setView(view === 'login' ? 'signup' : 'login')} style={styles.backLink}>Toggle Login/Signup</p>
                </div>
            </div>
        );
    }

    return (
        <div style={styles.container}>
            <header style={styles.header}>
                <div style={{display: 'flex', justifyContent: 'space-between', alignItems: 'center'}}>
                    <h1 style={styles.title} onClick={resetView}>NutriGen.</h1>
                    <button onClick={() => supabase.auth.signOut()} style={styles.logoutBtn}>Logout</button>
                </div>
            </header>

            <main>
                {analysisData ? (
                    <div>
                        <h2 style={styles.productHeading}>{productName}</h2>
                        <div style={{display: 'flex', gap: '10px', marginBottom: '20px'}}>
                            <button style={styles.btn} onClick={saveToDietPlan}>Add to Diet Plan</button>
                            <button style={{...styles.btn, background: '#444'}} onClick={resetView}>New Scan</button>
                        </div>
                        <Dashboard data={analysisData} onReset={resetView} />
                    </div>
                ) : view === 'choice' ? (
                    <div style={styles.choiceGrid}>
                        <div style={styles.optionCard} onClick={() => setView('scan')}>🔍 Barcode Search</div>
                        <div style={styles.optionCard} onClick={() => setView('quiz')}>📝 Health Quiz</div>
                    </div>
                ) : view === 'scan' ? (
                    <div style={styles.card}>
                        <h3>Product Analyzer</h3>
                        <input style={styles.input} placeholder="Enter Barcode" value={barcode} onChange={e => setBarcode(e.target.value)} onKeyDown={e => e.key === 'Enter' && handleBarcodeSearch()} />
                        <div style={{margin: '15px 0', color: '#666'}}>— OR —</div>
                        <input type="file" id="barcode-photo" hidden accept="image/*" onChange={handlePhotoUpload} />
                        <label htmlFor="barcode-photo" style={styles.btnSecondary}>
                            {isLoading ? "Processing..." : "Upload Barcode Photo"}
                        </label>
                        <button onClick={resetView} style={styles.backLink}>Go Back</button>
                    </div>
                ) : (
                    <div style={styles.card}>
                        <h3>Health Assessment</h3>
                        <div style={{textAlign: 'left'}}>
                            <label style={styles.label}>Primary Goal:</label>
                            <select value={goal} onChange={(e) => setGoal(e.target.value)} style={styles.input}>
                                {goals.map(g => <option key={g} value={g}>{g}</option>)}
                            </select>
                            <label style={styles.label}>Symptoms:</label>
                            <div style={{display: 'flex', gap: '8px', flexWrap: 'wrap'}}>
                                {symptomList.map(s => (
                                    <button key={s} onClick={() => setSymptoms(prev => prev.includes(s) ? prev.filter(i => i !== s) : [...prev, s])} 
                                        style={symptoms.includes(s) ? styles.tagActive : styles.tag}>{s}</button>
                                ))}
                            </div>
                        </div>
                        <button onClick={handleQuizSubmit} style={styles.btn}>{isLoading ? 'Analyzing...' : 'Analyze Health'}</button>
                        <button onClick={resetView} style={styles.backLink}>Go Back</button>
                    </div>
                )}
                {error && <p style={{color: '#ff4d4d', marginTop: '20px'}}>{error}</p>}
            </main>
        </div>
    );
}

const styles = {
    container: { maxWidth: '800px', margin: '0 auto', padding: '40px 20px', color: '#fff', fontFamily: 'sans-serif' },
    header: { marginBottom: '30px' },
    title: { fontSize: '2.5rem', fontWeight: '800', cursor: 'pointer' },
    card: { background: '#1a1a1a', padding: '30px', borderRadius: '20px', border: '1px solid #333' },
    input: { width: '100%', padding: '12px', margin: '10px 0', borderRadius: '10px', background: '#2d2d2d', border: '1px solid #444', color: '#fff', boxSizing: 'border-box' },
    btn: { background: '#38a169', color: '#fff', padding: '12px', width: '100%', borderRadius: '10px', border: 'none', fontWeight: 'bold', cursor: 'pointer', flex: 1 },
    btnSecondary: { background: '#2d3748', color: '#fff', padding: '12px', borderRadius: '10px', cursor: 'pointer', textAlign: 'center', display: 'block', width: '100%', boxSizing: 'border-box' },
    choiceGrid: { display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '20px' },
    optionCard: { padding: '50px 20px', background: '#1a1a1a', border: '1px solid #333', borderRadius: '20px', cursor: 'pointer', textAlign: 'center', fontSize: '1.2rem' },
    logoutBtn: { background: 'none', border: '1px solid #ff4d4d', color: '#ff4d4d', padding: '5px 15px', borderRadius: '8px', cursor: 'pointer' },
    backLink: { color: '#aaa', cursor: 'pointer', textAlign: 'center', marginTop: '15px', display: 'block', background: 'none', border: 'none', textDecoration: 'underline' },
    tag: { padding: '8px 16px', borderRadius: '20px', border: '1px solid #333', background: '#2d2d2d', color: '#ccc', cursor: 'pointer' },
    tagActive: { padding: '8px 16px', borderRadius: '20px', border: '1px solid #38a169', background: 'rgba(56, 161, 105, 0.2)', color: '#38a169' },
    label: { display: 'block', margin: '15px 0 5px', color: '#cbd5e0', fontWeight: 'bold' },
    productHeading: { color: '#38a169', textAlign: 'center', textTransform: 'capitalize' }
};

export default App;
